module multi_8bit
(
    input [7:0] A,
    input [7:0] B,
    output reg [15:0] product
);

reg [7:0] a, b;
reg [15:0] temp;

always @(*) begin
    a = A;
    b = B;
    temp = 0;
    for (int i = 0; i < 8; i++) begin
        if (b[i])
            temp = temp + (a << i);
    end
    product = temp;
end

endmodule
